export type ParsedDepositStakeInstruction<
  TProgram extends string = typeof PERPETUALS_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    owner: TAccountMetas[0];
    feePayer: TAccountMetas[1];
    fundingLpTokenAccount: TAccountMetas[2];
    transferAuthority: TAccountMetas[3];
    perpetuals: TAccountMetas[4];
    pool: TAccountMetas[5];
    flpStakeAccount: TAccountMetas[6];
    poolStakedLpVault: TAccountMetas[7];
    systemProgram: TAccountMetas[8];
    tokenProgram: TAccountMetas[9];
    eventAuthority: TAccountMetas[10];
    program: TAccountMetas[11];
    lpTokenMint: TAccountMetas[12];
  };
  data: DepositStakeInstructionData;
};

export function parseDepositStakeInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedDepositStakeInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 13) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 13,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      owner: getNextAccount(),
      feePayer: getNextAccount(),
      fundingLpTokenAccount: getNextAccount(),
      transferAuthority: getNextAccount(),
      perpetuals: getNextAccount(),
      pool: getNextAccount(),
      flpStakeAccount: getNextAccount(),
      poolStakedLpVault: getNextAccount(),
      systemProgram: getNextAccount(),
      tokenProgram: getNextAccount(),
      eventAuthority: getNextAccount(),
      program: getNextAccount(),
      lpTokenMint: getNextAccount(),
    },
    data: getDepositStakeInstructionDataDecoder().decode(instruction.data),
  };
}
